const EVENTS_DATA = {"curated": [15, 1, 27], "events": [{"id": 1, "date": "2026-03-18", "title": "央行开展205亿元逆回购操作 维持1.40%利率不变", "type": "公开市场操作", "abstract": "中国人民银行今日开展205亿元7天期逆回购操作，中标利率维持1.40%不变，延续此前货币政策工具的常规调控手段，以保持银行体系流动性合理充裕。", "risk": "-"}, {"id": 2, "date": "2026-03-18", "title": "湖南部署长株潭交通基础设施互联互通工程", "type": "区域政策变动", "abstract": "湖南省委书记沈晓明在2026年长株潭一体化发展领导小组会议上强调，将重点推进三市交通基础设施互联互通，通过构建环形成网的交通体系，促进区域一体化发展，让群众共享一体化成果。", "risk": "-"}, {"id": 3, "date": "2026-03-18", "title": "三部门启动有奖发票试点促消费，累计投放奖金18.5亿元", "type": "消费刺激", "abstract": "财政部、商务部、国家税务总局自2026年起在50个城市开展为期六个月的有奖发票试点活动，通过投放18.5亿元奖金吸引2.3亿人次参与，有效释放消费潜力并规范市场秩序。", "risk": "正面"}, {"id": 4, "date": "2026-03-18", "title": "江苏拟强化企业主导产学研协同创新促进产业链融合", "type": "区域政策变动", "abstract": "江苏省政府宣布将推动创新资源向企业集聚，通过强化企业主导的产学研协同创新机制，促进创新链、产业链、资金链、人才链深度融合，加速重大科技成果转化应用，助力企业提升核心竞争力，推动产业向全球价值链高端攀升。", "risk": "-"}, {"id": 5, "date": "2026-03-18", "title": "陕西出台企业上市服务机制支持初创企业成长", "type": "区域政策变动", "abstract": "陕西省委全面深化改革委员会会议提出完善企业上市'一对一'服务机制，通过科技型企业发展'四个工程'和科技金融服务'五项机制'改革，重点培育初创企业并推动其成长为本土领军企业，助力区域经济高质量发展。", "risk": "-"}, {"id": 6, "date": "2026-03-18", "title": "山西部署农村集体三资管理专项整治及集体经济培育", "type": "区域政策变动", "abstract": "山西省召开专项整治会议，强调通过规范农村集体资产资源管理、整治工程建设问题、盘活闲置资产等举措，推动高标准农田建设与新型农村集体经济因地制宜发展，强化农村集体资产效益提升。", "risk": "-"}, {"id": 7, "date": "2026-03-18", "title": "特朗普威胁退出北约以应对中东局势", "type": "中东局势动荡", "abstract": "美国总统特朗普因多国拒绝协助其组建国际联盟保障霍尔木兹海峡安全，对北约盟友提出批评，并威胁考虑退出北约，凸显中东地区地缘政治紧张局势。", "risk": "负面"}, {"id": 8, "date": "2026-03-18", "title": "中东冲突升级致美军调兵亚洲盟友，暴露安全承诺不足", "type": "中东局势动荡", "abstract": "中东地区冲突持续升级，美国为应对局势从韩国调离'萨德'反导系统并从日本调遣军舰至波斯湾，导致其亚洲盟友对美军安全保障能力产生质疑，凸显美军资源调配策略引发的区域安全信任危机。", "risk": "负面"}, {"id": 9, "date": "2026-03-18", "title": "中东地缘冲突冲击绍兴纺织市场", "type": "中东局势动荡", "abstract": "中东地区持续的地缘政治冲突导致国际纺织市场波动，绍兴柯桥纺织业作为中国纺织业重要基地，其布料交易市场虽表面平稳，但已面临外部环境压力，行业主体需应对潜在风险。", "risk": "负面"}, {"id": 10, "date": "2026-03-18", "title": "以色列空袭贝鲁特市中心引发中东局势紧张", "type": "中东局势动荡", "abstract": "当地时间18日凌晨，以色列军队对黎巴嫩首都贝鲁特实施四次空袭，目标包括市中心及南部郊区，导致当地多次发生爆炸，引发中东地区地缘政治冲突升级。", "risk": "负面"}, {"id": 11, "date": "2026-03-18", "title": "开平市政银协同推进乡村振兴金融服务下沉", "type": "乡村振兴", "abstract": "开平市通过金融机构结对支持镇村经济发展，推动金融服务下沉至基层，新增授信超30亿元，累计发放贷款25亿元，惠及5000余户经营主体，构建横向联动、纵向贯通的金融支持体系，探索政银协同助力乡村振兴新路径。", "risk": "正面"}, {"id": 12, "date": "2026-03-18", "title": "美国司法部拟封杀Anthropic AI服务以维护国家安全", "type": "海外禁令发布", "abstract": "美国司法部向法庭提交文件，以国家安全为由拟封杀Anthropic公司的人工智能技术服务条款，表明政府机构将不再接受其AI服务，此举可能涉及对AI技术出口的限制措施。", "risk": "负面"}, {"id": 13, "date": "2026-03-18", "title": "日本2月贸易顺差达573亿日元", "type": "海外重要经济数据发布", "abstract": "日本财务省公布数据显示，2023年2月日本国际贸易顺差为573亿日元，反映当月进出口贸易状况。", "risk": "-"}, {"id": 14, "date": "2026-03-18", "title": "日本2月出口增速放缓至4.2% 对美贸易顺差收窄", "type": "海外重要经济数据发布", "abstract": "日本政府公布数据显示，2023年2月出口额同比增长4.2%，较1月16.8%的增幅显著放缓，且低于市场预期的1.6%。受汽车、零部件及药品出口疲软影响，对美出口同比下降8.0%，导致对美贸易顺差收窄25.6%，反映特朗普关税政策的持续影响。", "risk": "-"}, {"id": 15, "date": "2026-03-18", "title": "美军空袭霍尔木兹海峡伊朗导弹阵地", "type": "中东局势动荡", "abstract": "美军中央司令部宣布使用5000磅钻地弹对霍尔木兹海峡沿岸伊朗导弹阵地实施打击，以消除对国际航运的威胁。此举反映美国在中东地区持续军事介入，加剧区域紧张局势。", "risk": "负面"}, {"id": 16, "date": "2026-03-18", "title": "美以对伊朗发起军事行动致高层伤亡", "type": "中东局势动荡", "abstract": "美国和以色列于2月28日对伊朗实施大规模军事行动，导致时任伊朗最高领袖哈梅内伊及多名军政高级官员在空袭中丧生，引发中东地区地缘政治冲突升级。", "risk": "负面"}, {"id": 17, "date": "2026-03-18", "title": "中东冲突升级加剧避险情绪，黄金价格承压震荡", "type": "中东局势动荡", "abstract": "中东地区持续升级的军事冲突引发避险情绪，叠加伊朗对阿联酋的袭击及霍尔木兹海峡能源危机，推动黄金价格在5000美元关口附近波动，市场关注美联储利率决议对金价的影响。", "risk": "负面"}, {"id": 18, "date": "2026-03-18", "title": "中东冲突引发柴油价格飙升致巴西卡车工会拟罢工", "type": "中东局势动荡", "abstract": "中东地区冲突导致柴油价格大幅上涨，巴西卡车司机工会主席表示该工会正计划本周举行罢工，以应对因能源成本上升引发的生存危机。此次罢工或重演2018年大规模交通瘫痪事件，凸显当前经济压力。", "risk": "负面"}, {"id": 19, "date": "2026-03-18", "title": "以军空袭致伊朗高官遇害 两国关系再起波澜", "type": "中东局势动荡", "abstract": "以色列国防军于17日夜间对伊朗首都德黑兰附近实施空袭，导致伊朗最高国家安全委员会秘书、伊斯兰议会前议长阿里·拉里贾尼遇害。伊朗总统佩泽希齐扬发表声明哀悼并誓言复仇，强调将继续坚持理性与远见相结合的抵抗路线，该事件加剧了中东地区地缘政治紧张局势。", "risk": "负面"}, {"id": 20, "date": "2026-03-18", "title": "韩国政府推出1.5万亿韩元小型企业财政支持计划", "type": "财政政策宽松", "abstract": "韩国政府宣布将向小型企业发放1.5万亿韩元财政支持，以缓解其经营压力并促进经济发展。该政策属于财政政策宽松范畴，通过增加政府支出直接刺激企业活力。", "risk": "正面"}, {"id": 21, "date": "2026-03-18", "title": "伊朗核电站遭敌方袭击 未造成设施及人员损失", "type": "中东局势动荡", "abstract": "伊朗原子能组织宣布，当地时间3月17日晚，一枚敌方投射物击中布什尔核电站厂区，但未造成设施损毁或人员伤亡。伊朗方指出该袭击违反国际法规，可能对地区安全产生重大影响。", "risk": "负面"}, {"id": 22, "date": "2026-03-18", "title": "澳大利亚10年期盈亏平衡通胀率升至2.306%", "type": "海外重要经济数据发布", "abstract": "澳大利亚10年期盈亏平衡通胀率上升5个基点至2.306%，该数据直接反映市场对未来通胀水平的预期变化，属于海外国家关键经济指标发布范畴。", "risk": "-"}, {"id": 23, "date": "2026-03-18", "title": "美叙商讨联合打击真主党武装行动遭叙利亚拒绝", "type": "中东局势动荡", "abstract": "美国曾向叙利亚政府提议派遣部队协助解除黎巴嫩真主党武装，但叙利亚因担忧卷入中东战争及加剧教派冲突而拒绝。该提议反映美以联合打击真主党的军事行动正在推进，真主党近期对以色列的军事行动已引发地区紧张局势升级。", "risk": "负面"}, {"id": 24, "date": "2026-03-18", "title": "路透短观调查：日本6月制造业与非制造业景气指数预计双升", "type": "海外重要经济数据发布", "abstract": "路透短观调查显示，日本6月制造业景气判断指数预计为正14，非制造业景气判断指数预计为正21，显示日本制造业和非制造业活动均呈现扩张态势。", "risk": "-"}, {"id": 25, "date": "2026-03-18", "title": "韩国2月经调整失业率2.9%低于预期", "type": "海外重要经济数据发布", "abstract": "韩国2月经调整失业率录得2.9%，低于市场预期的3.0%，显示该国就业市场呈现改善态势。", "risk": "-"}, {"id": 26, "date": "2026-03-18", "title": "巴林国王与特朗普通电话商讨伊朗袭击事件应对", "type": "中东局势动荡", "abstract": "巴林国王与美国总统特朗普通电话，就伊朗袭击事件进行紧急磋商，双方就地区安全局势及后续应对措施展开沟通。", "risk": "负面"}, {"id": 27, "date": "2026-03-18", "title": "美国依据1974年贸易法加征10%进口附加费", "type": "美国关税政策变动", "abstract": "美国政府依据《1974年贸易法》第122条，对所有贸易伙伴加征10%进口附加费，此举被认定为具有单边主义和保护主义色彩，引发中方坚决反制。", "risk": "-"}, {"id": 28, "date": "2026-03-18", "title": "政府工作报告出台服务出口支持政策促贸易发展", "type": "贸易政策宽松", "abstract": "2023年《政府工作报告》明确提出鼓励支持服务出口，通过扩大服务业开放、建设开放平台、推动服务贸易创新发展等政策安排，旨在优化服务贸易结构，释放发展潜能，推动我国服务贸易高质量发展。", "risk": "正面"}, {"id": 29, "date": "2026-03-18", "title": "新西兰第四季度经常帐赤字收窄至59.84亿纽元", "type": "海外重要经济数据发布", "abstract": "新西兰第四季度经常帐赤字为59.84亿纽元，较前值-83.65亿纽元有所收窄，显示该国国际收支状况有所改善。", "risk": "-"}, {"id": 30, "date": "2026-03-18", "title": "美国国务院要求全球使馆立即开展安全评估应对中东局势", "type": "中东局势动荡", "abstract": "美国国务院于3月17日要求全球所有驻外使馆立即开展安全评估，以应对中东地区持续紧张局势可能引发的外溢影响，此举旨在加强外交安全防护措施。", "risk": "负面"}]};
